CREATE OR REPLACE FUNCTION fpa_tel_lon_fristperiod (as_conno char) RETURNS bigint AS $body$
DECLARE

  ldc_period_pay bigint;

BEGIN
  /* ------------ หางวดแรกที่ส่งหัก ---------------*/

  begin
    select sc_lon_m_loan_request.period_payment_amount
    into STRICT ldc_period_pay
    from sc_lon_m_loan_request , sc_lon_m_contract
    where (sc_lon_m_contract.loan_requestment_no  = sc_lon_m_loan_request.loan_requestment_no )
    and (sc_lon_m_contract.loan_contract_no = as_conno);
  exception when others then ldc_period_pay :=0;
  end;
  if coalesce(ldc_period_pay::text, '') = '' or ldc_period_pay = 0 then
    begin
      select payment_amount into STRICT ldc_period_pay
      from sc_lon_m_loan_card_detail tld,sc_lon_m_loan_card
      where (tld.loan_contract_no = sc_lon_m_loan_card.loan_contract_no)
      and (exists (
        SELECT null from sc_lon_m_ucf_loan_card_item
        where tld.item_type_code = item_type_code
        and sign_status < 0
      ))
      and (sc_lon_m_loan_card.loan_contract_no = as_conno)
      order by tld.seq_no asc
       LIMIT 1;
    exception when others then ldc_period_pay := 0;
    end;
  end if;
  return coalesce(ldc_period_pay,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
